window.__QUIZ_DATA__=[{"id":"theory>Geography>2009>1>a","subject":"Geography","year":"2009","type":"Theory","sub_label":"a","group":"","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : MAP WORK","question":"Study the map extract on a scale of 1:50,000 and answer this  question    Draw an outline of the area to a scale of 1 : 150,000.","images":["data:image/png;base64,"],"marking_scheme":"Outline = 12.3 cm by 12.2 cm","marks":"8","difficulty":"3"},{"id":"theory>Geography>2009>1>b","subject":"Geography","year":"2009","type":"Theory","sub_label":"b","group":"CLOSENESS","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : MAP WORK","question":"On your outline, mark and name:  (i) a nodal settlement  (ii) one secondary road  (iii) the trigonometrical station northwest of Kaiama.","images":["data:image/png;base64,"],"marking_scheme":"(i) Nodal town (kaiama)  (ii) No secondary road shown on the topography map.  (iii) Trigonometrical station.","marks":"6","difficulty":"3"},{"id":"theory>Geography>2009>1>c","subject":"Geography","year":"2009","type":"Theory","sub_label":"c","group":"","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : MAP WORK","question":"Calculate the full length of the River Gbesha in the northeastern part of the map from point X.","images":[],"marking_scheme":"Length on the map 27.4cm (\u00b1 0.2cm)  Scale of map = 1 : 50,000  Therefore,lengthonground=27.4 \u00d7 50,000109,000  =27.4km2  \u21d2 13.7km \u00b1 0.2km:  (13.5 - 13.9km)","marks":"4","difficulty":"2"},{"id":"theory>Geography>2009>1>d>i","subject":"Geography","year":"2009","type":"Theory","sub_label":"i","group":"CLOSENESS","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : MAP WORK","question":"Identify two land use types in the mapped area.","images":[],"marking_scheme":"- Agriculture or farming because of scattered cultivation.  - Animal grazing because of Savanna.  - Transportation because of roads and paths.  - Settlements because of towns and villages.","marks":"1","difficulty":"2"},{"id":"theory>Geography>2009>1>d>ii","subject":"Geography","year":"2009","type":"Theory","sub_label":"ii","group":"CLOSENESS","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : MAP WORK","question":"Identify three social amenities in Kaiama.","images":[],"marking_scheme":"- Postal Agency - Mail  - Health centre - Health care  - Church - Religion  - Market - Trading  - Rent House - Hospitality/Tourism  - School - Education","marks":"1","difficulty":"1"},{"id":"theory>Geography>2009>2>a>i","subject":"Geography","year":"2009","type":"Theory","sub_label":"i","group":"CLOSENESS","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : PRINCIPLES OF ELEMENTARY SURVEYING","question":"Describe this surveying instrument:    ranging poles.","images":[],"marking_scheme":"- A ranging pole is between 1.8m - 3m in length.  - Made of light poles of circular section - 25 to 30mm in diameter  - Painted in alternate bright colours as white, red and black to make it visible from afar.  - The poles are made of light metals or seasoned wood.","marks":"5","difficulty":"1"},{"id":"theory>Geography>2009>2>a>ii","subject":"Geography","year":"2009","type":"Theory","sub_label":"ii","group":"CLOSENESS","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : PRINCIPLES OF ELEMENTARY SURVEYING","question":"Describe this surveying instrument:  chain","images":[],"marking_scheme":"- Every 5m and 10m of the chain also carries a different tag for identification.  - The handles from part of the distance.  - Brass handles from holding at the end of the chain.  - At every metre of the chain, there is a brass tag or tally to aid reading.  - They are formed by 100 pieces of wires.","marks":"2","difficulty":"1"},{"id":"theory>Geography>2009>2>a>iii","subject":"Geography","year":"2009","type":"Theory","sub_label":"iii","group":"CLOSENESS","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : PRINCIPLES OF ELEMENTARY SURVEYING","question":"Describe this surveying instrument:  cross staff","images":[],"marking_scheme":"- The arms are turned upwards at their ends   - The line of slight is between cross at right angles  - Each has slits   - Made of metals  - The head is mounted on a shortened version of a ranging pole.","marks":"3","difficulty":"1"},{"id":"theory>Geography>2009>2>a>iv","subject":"Geography","year":"2009","type":"Theory","sub_label":"iv","group":"CLOSENESS","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : PRINCIPLES OF ELEMENTARY SURVEYING","question":"Describe this surveying instrument:  arrows","images":[],"marking_scheme":"- Painted in bright colours to be easily seen.  - Bent at the top into a ring.  - About 381mm or 15 inches long.  - Thin pointed stell wires.  - About a easy view by putting red pieces of cloth.","marks":"2","difficulty":"1"},{"id":"theory>Geography>2009>2>b","subject":"Geography","year":"2009","type":"Theory","sub_label":"b","group":"CLOSENESS","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : PRINCIPLES OF ELEMENTARY SURVEYING","question":"Outline the process involved in carrying out a Chain Survey.","images":[],"marking_scheme":"Reconnaissance survey of the area:  - Sketch the map  - Chain surveying requires a surveyor and two assistants  - Surveyor stays at the starting point and a station is fixed.  - A lead chairman is in front while the other holds the chain at the zero end.  - Leader carries arrows and ranging poles.  - With the poles, he aligns the points and moves the chain to line.  - When the chain is steady of the zero point on station A, the lead chairman fixes an arrow at the end of the chain length.  - The leader then drags on the chain towards the station set following the same procedures.  - The distances measured are entered in the field notebook.  - Offsets are indicated   - The measured distances and offsets are plotted.","marks":"8","difficulty":"2"},{"id":"theory>Geography>2009>3>a>i","subject":"Geography","year":"2009","type":"Theory","sub_label":"i","group":"CLOSENESS","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : MAP WORK","question":"With the aid of a diagram, identify the main lines of latitude.","images":[],"marking_scheme":"Main lines of Latitudes  1. Equator (0\u00b0)  2. Artics circles (66 1/2\u00b0N)  3. Tropic of Cancer (23 1/2 \u00b0N)  4. Tropic of capricorn (23 1/2\u00b0S)  5. Antarctic circle (66 1/2\u00b0S)","marks":"8","difficulty":"2"},{"id":"theory>Geography>2009>3>a>ii","subject":"Geography","year":"2009","type":"Theory","sub_label":"ii","group":"","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : MAP WORK","question":"Calculate the distance between Addis Ababa in Ethopia (latitude 10\u00b0N) and Maseru in Lesotho (latitude 30\u00b0S).","images":["data:image/png;base64,"],"marking_scheme":"Latitude of Addis Ababa = 10\u00b0N  Latitude of Maseru = 30\u00b0S  Latitude difference = 10 + 30 = 40\u00b0  Since 1\u00b0 = 4 mins  So, 111km or 111.1km = 111 \u00d7 40\u00b0 or 111.1 \u00d7 400  \u21d2 4400km or 4444km","marks":"4","difficulty":"3"},{"id":"theory>Geography>2009>3>b>i","subject":"Geography","year":"2009","type":"Theory","sub_label":"i","group":"CLOSENESS","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : ELEMENTS OF PHYSICAL GEOGRAPHY","question":"Define revolution of the earth.","images":[],"marking_scheme":"Revolution of the earth is the movement of the earth round the sun on its orbit.","marks":"4","difficulty":"1"},{"id":"theory>Geography>2009>3>b>ii","subject":"Geography","year":"2009","type":"Theory","sub_label":"ii","group":"CLOSENESS","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : ELEMENTS OF PHYSICAL GEOGRAPHY","question":"Describe how revolution of earth affects the length of day and night in the Northern Hemisphere.","images":[],"marking_scheme":"- At the Arctic circle (66 1/2\u00b0N) there is a complete 24 hrs period of continuous day on june 21.  - The length of day and night varies depending on the position of the earth in relation to the sun.  - The \"sun never rises at the Arctic circle\".  - There is equal day and night during equinox.  - The sun is directly overhead at the equator on March 21 and September 23.","marks":"4","difficulty":"2"},{"id":"theory>Geography>2009>4>a","subject":"Geography","year":"2009","type":"Theory","sub_label":"a","group":"CLOSENESS","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : ROCKS","question":"Describe four characteristics of igneous rocks.","images":[],"marking_scheme":"- Formed from cooled and solidified magma.  - Do not contain fossils.  - Are either acidic or basic   - None stratified  - They are be formed beneath the earth as intrusive rocks. Examples are gabbro, granite e.t.c.  - They can otherwise be formed also on the surface of the earth as extrusive rocks.  - They contain crystals.","marks":"8","difficulty":"2"},{"id":"theory>Geography>2009>4>b","subject":"Geography","year":"2009","type":"Theory","sub_label":"b","group":"CLOSENESS","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : ROCKS","question":"Using specific examples, state four ways in which metamorphic rocks are useful to man.","images":[],"marking_scheme":"- Kaolin for ceramic products.  - Emeralds for Jewelry  - Marble for floor tiles.  - Graphite for lead pencils.  - Slate, marbles are minerals/raw materials for industries.","marks":"12","difficulty":"2"},{"id":"theory>Geography>2009>5>a","subject":"Geography","year":"2009","type":"Theory","sub_label":"a","group":"CLOSENESS","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : HYDROSPHERE","question":"With the aid of diagrams, describe the characteristics of this feature:    meanders.","images":["data:image/png;base64,"],"marking_scheme":"* Formed when the rivers are unable to go straight as a result of reduction in the river's velocity.  * Active erosion on the concave side.  * Deposition on the convex side.  * Where there is a wide flood plain.","marks":"8","difficulty":"3"},{"id":"theory>Geography>2009>5>b","subject":"Geography","year":"2009","type":"Theory","sub_label":"b","group":"CLOSENESS","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : HYDROSPHERE","question":"With the aid of diagrams, describe the characteristics of this feature:  flood plain.","images":["data:image/png;base64,"],"marking_scheme":"- This is a gently sloping plane of alluvium covering the valley floor along which the river flows in a meandering channel.   - Feature of middle/lower course of a river.  - Flood plain is made up of sediments deposited on low land areas of the river valley.  - Deposits are sorted-coanser materials are deposited before the finer ones.","marks":"6","difficulty":"3"},{"id":"theory>Geography>2009>5>c","subject":"Geography","year":"2009","type":"Theory","sub_label":"c","group":"CLOSENESS","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : HYDROSPHERE","question":"With the aid of diagrams, describe the characteristics of this feature:  braided stream.","images":["data:image/png;base64,"],"marking_scheme":"- Those depositions along the course of the river cause the river to break into several channels which later rejoin to form 'braided' stream.  - A feature of a lower course of a river.  - It starts with the building up of a complex tangle of channels.  - It has been blocked by deposit of sand bars on the flow of the river.","marks":"6","difficulty":"3"},{"id":"theory>Geography>2009>6>a","subject":"Geography","year":"2009","type":"Theory","sub_label":"a","group":"","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : STATISTICAL MAPS AND DIAGRAMS","question":"Use the statistics in the table below to answer this question  MonthsJFMAMJJASONDTemperature (\u00b0C)403021251040483025302015    Draw a Divergence Line Graph to represent the statistics.","images":["data:image/png;base64,"],"marking_scheme":"","marks":"10","difficulty":"3"},{"id":"theory>Geography>2009>6>b>i","subject":"Geography","year":"2009","type":"Theory","sub_label":"i","group":"FINAL","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : WEATHER AND CLIMATE","question":"Use the statistics in the table below to answer this question  MonthsJFMAMJJASONDTemperature (\u00b0C)403021251040483025302015    Calculate the annual range of temperature.","images":[],"marking_scheme":"Temperature of the hottest month - Temperature of the coldest month = (48\u00b0C - 10\u00b0C) = 38\u00b0C","marks":"8","difficulty":"2"},{"id":"theory>Geography>2009>6>b>ii","subject":"Geography","year":"2009","type":"Theory","sub_label":"ii","group":"CLOSENESS","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : STATISTICAL MAPS AND DIAGRAMS","question":"Use the statistics in the table below to answer this question  MonthsJFMAMJJASONDTemperature (\u00b0C)403021251040483025302015  State one other method of showing the statistics above.","images":[],"marking_scheme":"- Divided bar graph  - Simple bar graph  - Simple line graph","marks":"2","difficulty":"1"},{"id":"theory>Geography>2009>7>a","subject":"Geography","year":"2009","type":"Theory","sub_label":"a","group":"CLOSENESS","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : SOIL","question":"What is soil profile?","images":[],"marking_scheme":"A soil profile is the vertical section of the soil from the surface down to the bed rock or parent rock below.","marks":"6","difficulty":"1"},{"id":"theory>Geography>2009>7>b","subject":"Geography","year":"2009","type":"Theory","sub_label":"b","group":"","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : SOIL","question":"Draw a well labelled diagram of soil profile.","images":["data:image/png;base64,"],"marking_scheme":"","marks":"8","difficulty":"2"},{"id":"theory>Geography>2009>7>c","subject":"Geography","year":"2009","type":"Theory","sub_label":"c","group":"CLOSENESS","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : SOIL","question":"Describe the characteristics of the three zones of soil profile.","images":[],"marking_scheme":"A-Horizon  - It is the top soil.  - Most plants roots are anchored there.  - It is also known as the eluviation zone.  - Darker in colour than other zone.    B-Horizon  - It is the sub-soil  - Humus and other organic matter washed down from a-horizon are converted to inorganic compound.  - It is also called Zone of illuviation.  - rich in iron, aluminium and magnesium    C-Horizon  - It is called the parent material horizon.  - contains unweathered rocks.  - Contains materials from which A and B horizons are formed   - Underlain by hard unweathered rocks.","marks":"6","difficulty":"3"},{"id":"theory>Geography>2009>8>a","subject":"Geography","year":"2009","type":"Theory","sub_label":"a","group":"CLOSENESS","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : ENVIRONMENTAL CONSERVATION","question":"Define ecosystem.","images":[],"marking_scheme":"Ecosystem is the interaction/relationship between organism and their physical environment which the live.","marks":"5","difficulty":"1"},{"id":"theory>Geography>2009>8>b","subject":"Geography","year":"2009","type":"Theory","sub_label":"b","group":"CLOSENESS","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : ENVIRONMENTAL CONSERVATION","question":"Identify, with examples two main components of the ecosystem.","images":[],"marking_scheme":"Abiotic Component:  - The non-living component   - The physical component of which examples are soil, water, gases, sunlight e.t.c.    Biotic Component  - The living component  - The biological component which are plants and animals.","marks":"5","difficulty":"2"},{"id":"theory>Geography>2009>8>c","subject":"Geography","year":"2009","type":"Theory","sub_label":"c","group":"CLOSENESS","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : ENVIRONMENTAL CONSERVATION","question":"Describe the interdependence between the two main components identified in question (b) above.","images":[],"marking_scheme":"- All human activities are mainly carried out in the land.  - Plants depend on soil for support and nutrients.  - Dead plant  and animals are broken down to form soil by bacteria during decomposition.  - Food produced from the use of sunlight, water and other gases are consumed by animals.  - Soil, air, water provide habitat for living organisms.  - Through respiration and photosynthesis, gases like oxygen and carbon-dioxide are returned to nature.","marks":"5","difficulty":"3"},{"id":"theory>Geography>2009>8>d","subject":"Geography","year":"2009","type":"Theory","sub_label":"d","group":"CLOSENESS","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : ENVIRONMENTAL CONSERVATION","question":"In what two ways can environmental balance be achieved?","images":[],"marking_scheme":"- Carbon cycle.  - Hydrological (water) cycle.  - Food chain and Food web  - Reforestation.  - Mineral nutrient cycle.  - Nitrogen cycle.","marks":"5","difficulty":"2"},{"id":"theory>Geography>2009>9>a","subject":"Geography","year":"2009","type":"Theory","sub_label":"a","group":"CLOSENESS","topic":"REGIONAL GEOGRAPHY OF NIGERIA : TRANSPORTATION","question":"Write a geographical account of rail transport under this heading    economic importance.","images":[],"marking_scheme":"- Facilitates movement of people/labour/troops.  - Links different regions, thus promoting national integration.  - Conveys raw materials to factories.  - Opens up new areas for economic activities.  - Diffusion of innovations and ideas.  - Generates income  - Generate revenues  - Promote tourism.","marks":"8","difficulty":"3"},{"id":"theory>Geography>2009>9>b","subject":"Geography","year":"2009","type":"Theory","sub_label":"b","group":"CLOSENESS","topic":"ECONOMIC AND HUMAN GEOGRAPHY : TRANSPORTATION","question":"Write a geographical account of rail transport under this heading  problems.","images":[],"marking_scheme":"- Competitions from other modes of transportation e.g road and air   - Poor management/planning   - Inadequate capital  - Single track  - High cost of spare parts  - Not flexible  - Low patronage  - Narrow gauges  - Slow speed in developing countries.","marks":"6","difficulty":"3"},{"id":"theory>Geography>2009>9>c","subject":"Geography","year":"2009","type":"Theory","sub_label":"c","group":"CLOSENESS","topic":"ECONOMIC AND HUMAN GEOGRAPHY : TRANSPORTATION","question":"Write a geographical account of rail transport under this heading  solutions","images":[],"marking_scheme":"- Improved communication systems.  - Improved standard coaches.  - Loan from banks.  - Proper maintenance.  - Faster engines and coaches.  - Wider gauges to increase speed.  - Embankment to check steep gradient.","marks":"6","difficulty":"3"},{"id":"theory>Geography>2009>10>a>i","subject":"Geography","year":"2009","type":"Theory","sub_label":"i","group":"CLOSENESS","topic":"ECONOMIC AND HUMAN GEOGRAPHY : TRADE","question":"Name two major export items from your country.","images":[],"marking_scheme":"Items exported: Beverages, rubber, natural gas, hides and skin, petroleum, cocoa, columbites, soya beans, tin e.t.c.","marks":"2","difficulty":"1"},{"id":"theory>Geography>2009>10>a>ii","subject":"Geography","year":"2009","type":"Theory","sub_label":"ii","group":"CLOSENESS","topic":"ECONOMIC AND HUMAN GEOGRAPHY : TRADE","question":"Name two major import items to your country.","images":[],"marking_scheme":"Items Imported  Pasteries, textiles, computers, foods, machinery, motor vehicles, electronics, tractors e.t.c.","marks":"2","difficulty":"1"},{"id":"theory>Geography>2009>10>a>iii","subject":"Geography","year":"2009","type":"Theory","sub_label":"iii","group":"CLOSENESS","topic":"ECONOMIC AND HUMAN GEOGRAPHY : TRADE","question":"Name two major trading partners of your country.","images":[],"marking_scheme":"Trading partners: South Africa, Italy, Spain, Britain, Japan, USA, Canada, Germany, South korea, Taiwan, Belgium e.t.c.","marks":"2","difficulty":"1"},{"id":"theory>Geography>2009>10>b","subject":"Geography","year":"2009","type":"Theory","sub_label":"b","group":"CLOSENESS","topic":"ECONOMIC AND HUMAN GEOGRAPHY : TRADE","question":"Highlight four benefits your country derives from trading with other countries.","images":[],"marking_scheme":"- Development of infrastructure e.g port facilities.  - Stabilizes world prices.  - Growth of industry.  - Fosters international co-operation.  - Provision of foreign exchange.  - Provision of employment.  - Provision of new products.","marks":"8","difficulty":"2"},{"id":"theory>Geography>2009>10>c","subject":"Geography","year":"2009","type":"Theory","sub_label":"c","group":"CLOSENESS","topic":"ECONOMIC AND HUMAN GEOGRAPHY : TRADE","question":"Identify three problems encountered by your country in international trade.","images":[],"marking_scheme":"- Low demands for product.  - Ports congestion.  - Low value of currency.  - High tariffs on goods.  - Inadequate capital.  - Political instability.  - High cost of transportation.","marks":"6","difficulty":"2"},{"id":"theory>Geography>2009>11>a","subject":"Geography","year":"2009","type":"Theory","sub_label":"a","group":"CLOSENESS","topic":"ECONOMIC AND HUMAN GEOGRAPHY : INDUSTRY","question":"State four reasons for the concentration of manufacturing industries in the capital cities of Tropical African countries.","images":[],"marking_scheme":"- Availability of capital.  - Availabilty of labour.  - Power supply.  - Presence of large market.  - Availability of raw materials.  - Presence of infrastructural facilities.","marks":"8","difficulty":"3"},{"id":"theory>Geography>2009>11>b","subject":"Geography","year":"2009","type":"Theory","sub_label":"b","group":"","topic":"ECONOMIC AND HUMAN GEOGRAPHY : INDUSTRY","question":"Give three reasons for the predominance of consumer oriented industries in Tropical Africa.","images":[],"marking_scheme":"- High technology insufficiency  - High demand for products  - Inadequate skilled labour  - Availability of raw materials  - Inadequate capital  - Poor transportation network.","marks":"6","difficulty":"2"},{"id":"theory>Geography>2009>11>c","subject":"Geography","year":"2009","type":"Theory","sub_label":"c","group":"CLOSENESS","topic":"ECONOMIC AND HUMAN GEOGRAPHY : INDUSTRY","question":"Describe three contributions of manufacturing industries to the economic development of Tropical African countries.","images":[],"marking_scheme":"- Provision of employment opportunity.  - Development of infrastructure  - Improved standard of living  - Transfer of technology  - Increase in gross national product (GNP)  - Revenue generation  - Increases good and services  - Diversification of other sectors of the economy.","marks":"6","difficulty":"3"},{"id":"theory>Geography>2009>12>a","subject":"Geography","year":"2009","type":"Theory","sub_label":"a","group":"CLOSENESS","topic":"REGIONAL GEOGRAPHY OF NIGERIA : PHYSICAL SETTING","question":"Draw an outline map of Nigeria.  On the map, show the annual distribution of rainfall.","images":["data:image/png;base64,"],"marking_scheme":"Rainfall Zones  (a) Over 300cm  (b) 200 - 300cm  (c) 100 - 200cm  (d) Under 100cm  (e) 150 - 200cm (highland or plateau)","marks":"10","difficulty":"2"},{"id":"theory>Geography>2009>12>b","subject":"Geography","year":"2009","type":"Theory","sub_label":"b","group":"CLOSENESS","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : VEGETATION","question":"Highlight three effects of rainfall on the distribution of vegetation in Nigeria.","images":[],"marking_scheme":"- Commencement of rain marks the beginning of the growth of grasses.  - As rain decreases northwards, density of vegetation decreases.  - Area which have rainfall that is less than 300mm produce desert vegetation.  - High and continuous rainfall gives rise to evergreen vegetation.  - Areas which have rainfall under 500m produce Sahel Savanna type of vegetation.  - Areas which have rainfall between 1000m and 1500mm produce Guinea Savanna type of vegetation.  - High rainfall areas of over 2000mm rainfall give rise to forest vegetation.","marks":"6","difficulty":"2"},{"id":"theory>Geography>2009>12>c","subject":"Geography","year":"2009","type":"Theory","sub_label":"c","group":"CLOSENESS","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : VEGETATION","question":"Describe four characteristics of the Guinea Savanna.","images":[],"marking_scheme":"- It is the largest of all vegetation belts in Nigeria.  - Trees are deciduous  - Tall grasses  - Trees have thick barks  - They have long tap roots.  - Grasses are green during raining season and turn brown in the dry season.","marks":"4","difficulty":"2"},{"id":"theory>Geography>2009>13>a","subject":"Geography","year":"2009","type":"Theory","sub_label":"a","group":"CLOSENESS","topic":"REGIONAL GEOGRAPHY OF NIGERIA : AGRICULTURE","question":"Draw an outline map of Nigeria. On the map, locate and name:  (i) three major soil zones  (ii) an important crop associated with each zone;  (iii) an important town in any two of the zones.","images":["data:image/png;base64,"],"marking_scheme":"SOIL ZONES  - Zone of alluvial soils.  - Northern zone of sandy soils.  - Interior zone of interite soils.  - Southern zone of forest soils.    CROPS:  Millet, maize, cotton, Groundnut, guinea corn e.t.c, (Sandy soils).  Zone of Interite soils: Cassava, cocoyam, guinea corn, yam e.t.c.  Zone of forest soils: Cocoa, kolanut, oil palm, banana, rubber e.t.c.  Zone of alluvial soils: Cassava, cocoyam, swamp rice, yam e.t.c.    TOWNS  Sandy soils: Maiduguri, Sokoto, Kano e.t.c.  Zone of laterite soils: Kaduna, Abuja, Jos e.t.c.  Zone of forest soils: Benin, Ibadan, Akure, Aba e.t.c.  Zone of alluvial soils: Lokoja, Onitsha, Warri, Makurdi e.t.c.","marks":"10","difficulty":"3"},{"id":"theory>Geography>2009>13>b","subject":"Geography","year":"2009","type":"Theory","sub_label":"b","group":"CLOSENESS","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : SOIL","question":"Describe the characteristic features of any two of the soil zones shown in question (a)(i).","images":[],"marking_scheme":"1. Northern Zone of Sandy Soil  - Soils are fertile  - Soils are dark in colour  - Soils are not heavily leached  - Found in the northern parts of the country  - Soils grains are coarse in texture.    2. Interior Zone of laterite soils  - Generally sticky when wet and hard when dry.  - They are impervious  - They are heavily leached  - They are of medium fertility  - Usually reddish or brownish in colour.    3. Alluvial soils  - Support growth of rice, sugar cane, cassava e.t.c  - Soils are fine grained  - Rich in humus   - Underlain by clay  - Derived from weathered materials    4. Forest soils  - Support growth of economic trees  - Some are acidic  - Heavily leached  - Rich in humus  - Found in southern part of Nigeria.","marks":"10","difficulty":"3"},{"id":"theory>Geography>2009>14>a","subject":"Geography","year":"2009","type":"Theory","sub_label":"a","group":"CLOSENESS","topic":"REGIONAL GEOGRAPHY OF NIGERIA : AGRICULTURE","question":"Draw a sketch map of Nigeria.   On the map, mark and name:  (i) one cattle rearing  zone  (ii) one town in the zone  (iii) using arrows, show the movement of cattle from the producing area to two consuming markets.","images":["data:image/png;base64,"],"marking_scheme":"i. Cattle rearing zone  - Kano  - Borno  - Bauchi &nbsp &nbsp &nbsp &nbsp } Sudan Savanna Zone  - Sokoto  - Jos    ii. Towns in the zone:  - Bauchi  - Kano  - Sokoto  - Maiduguri  - Damaturi e.t.c.    iii. Direction to consuming area  - Ibadan  - To Abuja  - To Lagos  - To Port Harcourt","marks":"12","difficulty":"3"},{"id":"theory>Geography>2009>14>b","subject":"Geography","year":"2009","type":"Theory","sub_label":"b","group":"CLOSENESS","topic":"REGIONAL GEOGRAPHY OF NIGERIA : AGRICULTURE","question":"Highlight three factors that favour cattle rearing in the area shown in question (a)(i).","images":[],"marking_scheme":"- Availability of veterinary services  - Presence of resistant breeds  - Home of the Fulani-traditional cattle rearers  - Rolling/undulating plain  - Absence of tsetse-fly  - Cattle as a symbol of wealth","marks":"4","difficulty":"2"},{"id":"theory>Geography>2009>14>c","subject":"Geography","year":"2009","type":"Theory","sub_label":"c","group":"CLOSENESS","topic":"REGIONAL GEOGRAPHY OF NIGERIA : AGRICULTURE","question":"Outline three problems of cattle rearing in the area shown in (a)(i).","images":[],"marking_scheme":"- Cattle rustling/stealing   - Conflict with farmers  - Inadequate drugs and vaccines  - Overgrazing of pasture  - Presence of tse tse fly in some areas  - Poor transportation system  - Poor knowledge of modern ranching.","marks":"4","difficulty":"2"},{"id":"theory>Geography>2009>15>a","subject":"Geography","year":"2009","type":"Theory","sub_label":"a","group":"","topic":"REGIONAL GEOGRAPHY OF AFRICA : AFRICA ON BROAD OUTLINE","question":"Draw an outline map of West Africa. On it locate and name:  (i) one area of dense population   (ii) one area of sparse population  (iii) an important town in each area.  (iv) the River Niger","images":["data:image/png;base64,"],"marking_scheme":"","marks":"10","difficulty":"3"},{"id":"theory>Geography>2009>15>b","subject":"Geography","year":"2009","type":"Theory","sub_label":"b","group":"CLOSENESS","topic":"REGIONAL GEOGRAPHY OF AFRICA : AFRICA ON BROAD OUTLINE","question":"Explain four factors that have led to the high density of population in the area shown on your map.","images":[],"marking_scheme":"- Port location  - Soil  - Relief  - Mineral  - Migration  - Presence of social amenities  - Cash crop production","marks":"8","difficulty":"2"},{"id":"theory>Geography>2009>15>c","subject":"Geography","year":"2009","type":"Theory","sub_label":"c","group":"CLOSENESS","topic":"ECONOMIC AND HUMAN GEOGRAPHY : WORLD POPULATION","question":"Highlight two problems of sparse population density.","images":[],"marking_scheme":"- Vulnerable to external attack  - Low Gross Domestic Product (GDP)  - Low revenue to government  - Low productivity  - Low labour force  - Limited market","marks":"2","difficulty":"2"},{"id":"theory>Geography>2009>16>a","subject":"Geography","year":"2009","type":"Theory","sub_label":"a","group":"","topic":"REGIONAL GEOGRAPHY OF AFRICA : AFRICA ON BROAD OUTLINE","question":"Draw a sketch map of Africa. On the map, mark and name:  (i) River Nile and Limpopo  (ii) Lakes Victoria and Chad  (iii) Namib and Kalahari deserts","images":["data:image/png;base64,"],"marking_scheme":"","marks":"6","difficulty":"3"},{"id":"theory>Geography>2009>16>b","subject":"Geography","year":"2009","type":"Theory","sub_label":"b","group":"CLOSENESS","topic":"REGIONAL GEOGRAPHY OF AFRICA : SELECTED TOPICS","question":"Outline four uses of rivers and lakes in Africa.","images":[],"marking_scheme":"- Sources of food supply  - Means of transportation  - Tourism  - For domestic use  - Industrial uses  - Alluvial soils for agriculture  - Recreation  - Irrigation purpose","marks":"8","difficulty":"2"},{"id":"theory>Geography>2009>16>c","subject":"Geography","year":"2009","type":"Theory","sub_label":"c","group":"CLOSENESS","topic":"REGIONAL GEOGRAPHY OF AFRICA : SELECTED TOPICS","question":"Highlight four factors that limit the use of rivers in Africa.","images":[],"marking_scheme":"- Many rivers flowing through up productive areas.  - Seasonal fluctuations  - Silting of river mouths  - Rapids and waterfalls  - Presence of weeds   - Problems of river flowing through international boundaries.","marks":"4","difficulty":"2"},{"id":"theory>Geography>2009>17>a","subject":"Geography","year":"2009","type":"Theory","sub_label":"a","group":"","topic":"REGIONAL GEOGRAPHY OF AFRICA : AFRICA ON BROAD OUTLINE","question":"Draw a sketch map of Africa.  On the map, mark and name:  (i) the Rivers Niger and Nile  (ii) two areas of irrigation agriculture along each river.","images":["data:image/png;base64,"],"marking_scheme":"Areas  * Niger River  - Inland Niger Delta at Mali  - Along the river banks in Nigeria    * Nile River/R. Nile  - Aswan area  - Geizira in Sudan  - Delta area","marks":"10","difficulty":"3"},{"id":"theory>Geography>2009>17>b","subject":"Geography","year":"2009","type":"Theory","sub_label":"b","group":"CLOSENESS","topic":"REGIONAL GEOGRAPHY OF NIGERIA : AGRICULTURE","question":"Outline three contributions of irrigation agriculture to any of the areas shown in question (a)(ii).","images":[],"marking_scheme":"- Growth of Settlements  - Income to farmers  - Provision of food  - Water is provided for small scale farming  - Tourist attraction  - Employment opportunities  - Raw materials for industries  - Revenue to government","marks":"4","difficulty":"2"},{"id":"theory>Geography>2009>17>c","subject":"Geography","year":"2009","type":"Theory","sub_label":"c","group":"CLOSENESS","topic":"REGIONAL GEOGRAPHY OF NIGERIA : AGRICULTURE","question":"Highlight three problems facing irrigation agriculture in the area chosen in question 9(b).","images":[],"marking_scheme":"- Irrigation equipment are expensive to maintain.  - Fluctuation of water volume.  - Excessive evaporation causes salinity.  - High cost of constructing darms.  - Growth of aquatic weeds.  - Silting of dams.  - Pests affecting crops.","marks":"6","difficulty":"2"}];